tasks.solution:
// Jenkinsfile (commit to repo root as 'Jenkinsfile', no extension):
pipeline {
    agent any
    stages {
        stage('Checkout') {
            steps {
                checkout scm
            }
        }
    }
}

// Steps to apply 'Pipeline script from SCM':
// 1. In Jenkins: open the pipeline job → Configure
// 2. Pipeline section → Definition: 'Pipeline script from SCM'
// 3. SCM: Git
//    Repository URL: https://gitlab.com/<your-namespace>/<your-project>.git
//    Credentials: select or add the GitLab credentials
//    Branch: */dev (or */main)
//    Script Path: Jenkinsfile
// 4. Save
//
// Commit and push Jenkinsfile:
// git add Jenkinsfile
// git commit -m "Add Jenkinsfile with Checkout stage"
// git push
//
// Jenkins receives the webhook (from Lecture 3), reads Jenkinsfile from GitLab,
// and runs the Checkout stage. Console Output should show:
// 'Checking out Revision <SHA> (refs/remotes/origin/dev)'
// Stage View: one green 'Checkout' box.

